export const InterceptorClass: React.FC<InterceptorClassProps> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent =
    mode === 'light' ? InterceptorClassLight : InterceptorClassDark;

  return (
    <SvgComponent
